import{_ as a,o,c as r,ag as i}from"./chunks/framework.DM0yugQT.js";const g=JSON.parse('{"title":"Releasing a new OSRM version","description":"","frontmatter":{},"headers":[],"relativePath":"releasing.md","filePath":"releasing.md"}'),t={name:"releasing.md"};function n(s,e,l,c,d,h){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="releasing-a-new-osrm-version" tabindex="-1">Releasing a new OSRM version <a class="header-anchor" href="#releasing-a-new-osrm-version" aria-label="Permalink to &quot;Releasing a new OSRM version&quot;">​</a></h1><p>We are using <a href="http://semver.org/" target="_blank" rel="noreferrer">http://semver.org/</a> for versioning with major, minor and patch versions.</p><h2 id="guarantees" tabindex="-1">Guarantees <a class="header-anchor" href="#guarantees" aria-label="Permalink to &quot;Guarantees&quot;">​</a></h2><p>We are giving the following guarantees between versions:</p><h3 id="major-version-change" tabindex="-1">Major version change <a class="header-anchor" href="#major-version-change" aria-label="Permalink to &quot;Major version change&quot;">​</a></h3><ul><li>There are no guarantees about compatiblity of APIs or datasets</li><li>Breaking changes will be noted as <code>BREAKING</code> in the changelog</li></ul><h3 id="minor-version-change" tabindex="-1">Minor version change <a class="header-anchor" href="#minor-version-change" aria-label="Permalink to &quot;Minor version change&quot;">​</a></h3><p>We may introduce forward-compatible changes: query parameters and response properties may be added in responses, but existing properties may not be changed or removed. One exception to this is the addition of new turn types, which we see as forward-compatible changes.</p><ul><li>Forward-compatible HTTP API</li><li>Forward-compatible C++ library API</li><li>Forward-compatible node-osrm API</li><li>No compatiblity between OSRM datasets (needs new processing)</li></ul><h3 id="patch-version-change" tabindex="-1">Patch version change <a class="header-anchor" href="#patch-version-change" aria-label="Permalink to &quot;Patch version change&quot;">​</a></h3><ul><li>No change of query parameters or response formats</li><li>Compatible HTTP API</li><li>Compatible C++ library API</li><li>Compatible node-osrm API</li><li>Compatible OSRM datasets</li></ul><h2 id="release-and-branch-management" tabindex="-1">Release and branch management <a class="header-anchor" href="#release-and-branch-management" aria-label="Permalink to &quot;Release and branch management&quot;">​</a></h2><ul><li>The <code>master</code> branch is for the bleeding edge development</li><li>We create and maintain release branches <code>x.y</code> to control the release flow</li><li>We create the release branch once we create release branches once we want to release the first RC</li><li>RCs go in the release branch, commits needs to be cherry-picked from master</li><li>No minor or major version will be released without a code-equal release candidates</li><li>For quality assurance, release candidates need to be staged beforing tagging a final release</li><li>Patch versions may be released without a release candidate</li><li>We may backport fixes to older versions and release them as patch versions</li></ul><h2 id="releasing-a-version" tabindex="-1">Releasing a version <a class="header-anchor" href="#releasing-a-version" aria-label="Permalink to &quot;Releasing a version&quot;">​</a></h2><ol><li>Check out the appropriate release branch <code>x.y</code></li><li>Make sure <code>CHANGELOG.md</code> is up to date.</li><li>Make sure the <code>package.json</code> on branch <code>x.y</code> has been committed.</li><li>Make sure all tests are passing (e.g. Github Actions CI gives you a ✔️)</li><li>Use an annotated tag to mark the release: <code>git tag vx.y.z -a</code> Body of the tag description should be the changelog entries. Commit should be one in which the <code>package.json</code> version matches the version you want to release.</li><li>Use <code>npm run docs</code> to generate the API documentation. Copy <code>build/docs/*</code> to <code>https://github.com/Project-OSRM/project-osrm.github.com</code> in the <code>docs/vN.N.N/api</code> directory</li><li>Push tags and commits: <code>git push; git push --tags</code></li><li>On <a href="https://github.com/Project-OSRM/osrm-backend/releases" target="_blank" rel="noreferrer">https://github.com/Project-OSRM/osrm-backend/releases</a> press <code>Draft a new release</code>, write the release tag <code>vx.y.z</code> in the <code>Tag version</code> field, write the changelog entries in the <code>Describe this release</code> field and press <code>Publish release</code>. Note that Github Actions CI deployments will create a release when publishing node binaries, so the release may already exist. In which case the description should be updated with the changelog entries.</li><li>If not a release-candidate: Write a mailing-list post to <a href="mailto:osrm-talk@openstreetmap.org" target="_blank" rel="noreferrer">osrm-talk@openstreetmap.org</a> to announce the release</li><li>Wait until the Github Actions build has been completed and check if the node binaries were published by doing: <code>rm -rf node_modules &amp;&amp; npm install</code> locally.</li><li>For final releases run <code>npm publish</code> or <code>npm publish --tag next</code> for release candidates.</li><li>Bump version in <code>package.json</code> to <code>{MAJOR}.{MINOR+1}.0-unreleased</code> on the <code>master</code> branch after the release.</li></ol>',15)])])}const p=a(t,[["render",n]]);export{g as __pageData,p as default};
